{
    return func(x, y);
}

// Function that takes two integers as arguments and returns their sum
int sum(int x, int y)
{
    return x + y;
}

int main()
{
    // Create a function pointer that points to the sum function
    FuncPtr func = &sum;

    // Call the add function with the function pointer as an argument
